package com.google.gson.internal;
import java.util.Objects;

import org.junit.jupiter.api.Test;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import static org.junit.jupiter.api.Assertions.*;

class $Gson$PreconditionsTest {

    @Test
    void checkArgument_withTrueCondition_doesNotThrow() {
        // Should not throw any exception
        $Gson$Preconditions.checkArgument(true);
    }

    @Test
    void checkArgument_withFalseCondition_throwsIllegalArgumentException() {
        assertThrows(IllegalArgumentException.class, () -> $Gson$Preconditions.checkArgument(false));
    }

    @Test
    void privateConstructor_invocation() throws NoSuchMethodException, InvocationTargetException, InstantiationException, IllegalAccessException {
        Method constructor = $Gson$Preconditions.class.getDeclaredConstructors()[0];
        constructor.setAccessible(true);
        // Just invoke to cover private constructor
        constructor.invoke((Object) null);
    }
}
